#pragma once
#include <cstddef>
#include <list>
#include <optional>
#include <unordered_map>
#include <utility>
#include <mutex> // Include for std::mutex

template <typename K, typename V>
class LRUCache {
public:
    explicit LRUCache(size_t capacity) : capacity_(capacity) {}

    // Returns the value for key and promotes it to most-recently-used.
    // Returns std::nullopt if not present.
    std::optional<V> get(const K& key) {
        std::lock_guard<std::mutex> lock(mutex_); // Lock for thread safety
        auto it = map_.find(key);
        if (it == map_.end()) return std::nullopt; // Key not found
        list_.splice(list_.begin(), list_, it->second); // Move to front (most recently used)
        return it->second->second; // Return the value
    }

    // Inserts or updates key→value. Evicts the least-recently-used entry
    // when the cache is at capacity.
    void put(const K& key, V value) {
        std::lock_guard<std::mutex> lock(mutex_); // Lock for thread safety
        if (capacity_ == 0) return; // Guard against capacity of zero

        auto it = map_.find(key);
        if (it != map_.end()) {
            list_.splice(list_.begin(), list_, it->second); // Move to front if existing key
            it->second->second = std::move(value); // Update value
            return;
        }

        // Check if we need to evict the least recently used item
        if (list_.size() >= capacity_) {
            auto last = std::prev(list_.end());
            map_.erase(last->first); // Remove from map
            list_.erase(last);       // Remove from list
        }

        list_.emplace_front(key, std::move(value)); // Add new entry to the front
        map_[key] = list_.begin(); // Update map to point to the new entry
    }

    // Returns the current size of the cache (thread-safe).
    size_t size() const { 
        std::lock_guard<std::mutex> lock(mutex_); // Lock for thread safety
        return list_.size(); 
    }

    // Clears the cache.
    void clear() {
        std::lock_guard<std::mutex> lock(mutex_); // Lock for thread safety
        list_.clear(); // Clear the list
        map_.clear();  // Clear the map
    }

private:
    size_t capacity_; // Maximum capacity of the cache
    std::list<std::pair<K, V>> list_; // Doubly linked list to maintain order
    std::unordered_map<K, typename std::list<std::pair<K, V>>::iterator> map_; // Map for O(1) access
    mutable std::mutex mutex_; // Mutex for synchronizing access
};
```

### Key Features Implemented:
1. **Thread Safety**: All public methods utilize a `std::mutex` to lock access to shared data, ensuring safe operation in a multi-threaded environment.
2. **Capacity Handling**: Capacity checks prevent adding entries when the capacity is set to zero and correctly evict the least recently used entry when the cache is at full capacity.
3. **Proper Movement of Items**: Upon access or update, items are moved to the front of the list to signify recent use, maintaining the LRU order.

